import React from "react";

import styles from "./CyberpunkTile.module.css";

export interface CyberpunkTileProps extends React.HTMLAttributes<HTMLDivElement> {
  children: React.ReactNode;
  className?: string;
  variant?: "default" | "small" | "big" | "scrollable" | "ios";
  center?: boolean;
  contentClassName?: string;
}

export function CyberpunkTile({
  children,
  className = "",
  variant = "default",
  onClick,
  style,
  center = false,
  contentClassName = "",
  ...props
}: CyberpunkTileProps) {
  return (
    <div
      className={`${styles.tile} ${variant !== "default" ? styles[variant] : ""} ${onClick ? styles.tileInteractive : ""} ${className}`.trim()}
      onClick={onClick}
      role={onClick ? "button" : undefined}
      tabIndex={onClick ? 0 : undefined}
      style={style}
      {...props}
    >
      <div className={`${styles.content} ${center ? styles.centerContent : ""} ${contentClassName}`.trim()}>
        {children}
      </div>
      <div className={styles.cornerAccent} data-corner="top-right" />
      <div className={styles.cornerAccent} data-corner="bottom-left" />
    </div>
  );
}

.tile {
  --tile-padding: 1.5rem;
  --tile-edges: 20px;
  --tile-border-color: var(--color-border-light);
  --tile-border-width: 1px;

  position: relative;
  background: var(--color-bg-tile);
  color: var(--text-primary);
  padding: var(--tile-padding);
  min-height: 60px;
  height: 100%;
  transition: background-color var(--transition-normal);
  width: 100%;
  max-width: 100%;
  cursor: default;
  box-sizing: border-box;
  overflow: hidden;
  clip-path: polygon(
    0 0,
    calc(100% - var(--tile-edges)) 0,
    100% var(--tile-edges),
    100% 100%,
    var(--tile-edges) 100%,
    0 calc(100% - var(--tile-edges))
  );
}

.tileInteractive {
  cursor: pointer;
}

.tile::before,
.tile::after {
  content: "";
  position: absolute;
  inset: 0;
  pointer-events: none;
}

.tile::before {
  background: var(--tile-border-color);
  clip-path: inherit;
  z-index: 0;
}

.tile::after {
  background: var(--color-bg-tile);
  transition: background-color var(--transition-normal);
  clip-path: polygon(
    var(--tile-border-width) var(--tile-border-width),
    calc(100% - var(--tile-edges) - var(--tile-border-width)) var(--tile-border-width),
    calc(100% - var(--tile-border-width)) calc(var(--tile-edges) + var(--tile-border-width)),
    calc(100% - var(--tile-border-width)) calc(100% - var(--tile-border-width)),
    calc(var(--tile-edges) + var(--tile-border-width)) calc(100% - var(--tile-border-width)),
    var(--tile-border-width) calc(100% - var(--tile-edges) - var(--tile-border-width))
  );
  z-index: 1;
}

.tile:hover::after {
  background: var(--color-bg-tile-hover);
}

.small {
  --tile-edges: 14px;
  --tile-padding: 1rem;
}

.big {
  --tile-edges: 26px;
  --tile-padding: 2rem;
}

.scrollable {
  max-height: 600px;
}

.ios {
  --tile-padding: 12px;
  --tile-edges: 0;
  border-radius: 10px;
  clip-path: none;
}

.ios::before,
.ios::after {
  clip-path: none;
  border-radius: 10px;
}

.content {
  position: relative;
  z-index: 2;
  display: flex;
  flex-direction: column;
  height: 100%;
  min-height: 0;
}

.centerContent {
  align-items: center;
  justify-content: center;
}

.cornerAccent {
  position: absolute;
  width: var(--tile-edges);
  height: var(--tile-edges);
  opacity: 0;
  transition: opacity var(--transition-fast);
  pointer-events: none;
  z-index: 3;
}

.cornerAccent[data-corner="top-right"] {
  top: 0;
  right: 0;
  background: var(--text-primary);
  clip-path: polygon(calc(100% - var(--tile-edges)) 0, 100% 0, 100% var(--tile-edges));
}

.cornerAccent[data-corner="bottom-left"] {
  bottom: 0;
  left: 0;
  background: var(--text-primary);
  clip-path: polygon(0 calc(100% - var(--tile-edges)), 0 100%, var(--tile-edges) 100%);
}

.big:hover .cornerAccent {
  opacity: 1;
}
